import { useEffect, useState } from "react";
import api from "../api";

export default function Dashboard({ adminKey }) {
  const [youth, setYouth] = useState([]);

  useEffect(() => {
    const fetchYouth = async () => {
      try {
        const res = await api.get("/", {
          headers: { "x-admin-key": adminKey },
        });
        setYouth(res.data);
      } catch (err) {
        alert("Failed to load dashboard");
      }
    };

    fetchYouth();
  }, [adminKey]);

  const total = youth.length;
  const checkedIn = youth.filter((y) => y.checkedIn).length;
  const notChecked = total - checkedIn;

  return (
    <div className="dashboard">

      <h1>Youth Convention Dashboard</h1>

      <div className="stats">

        <div className="card">
          <h3>Total Registered</h3>
          <p>{total}</p>
        </div>

        <div className="card green">
          <h3>Checked In</h3>
          <p>{checkedIn}</p>
        </div>

        <div className="card orange">
          <h3>Not Checked In</h3>
          <p>{notChecked}</p>
        </div>

      </div>

      <h2>Recent Registrations</h2>

      <div className="recent">

        {youth.slice(0, 5).map((y) => (
          <div key={y._id} className="recent-item">
            <strong>{y.fullName}</strong>
            <span>{y.congregation}</span>
            <span>{y.phone}</span>
          </div>
        ))}

      </div>

    </div>
  );
}
